import { Text, View, Image, StyleSheet } from 'react-native';
import { useRoute } from '@react-navigation/native';
import { TouchableOpacity } from 'react-native';
import { useNavigation } from '@react-navigation/native';
import React, { useState, useEffect } from 'react';

function PokedexDetails() {
  const route = useRoute();
  const { id } = route.params;
  const [data, setData] = useState(null);
  const navigation = useNavigation();

  const fetchData = (pokemonId) => {
    fetch(`https://pokebuildapi.fr/api/v1/pokemon/${pokemonId}`)
      .then(response => response.json())
      .then(jsonData => setData(jsonData))
      .catch(error => console.error(error));
  };

  useEffect(() => {
    fetchData(id);
  }, [id]);

  console.log(data["apiTypes"]);

  const handlePokemonPress = (pokemonId) => {
    navigation.navigate('PokedexDetails', { id: pokemonId });
  };

  return (
    <>
      {data != null ? (
        <View key={data.id}>
          <Text>{data.name}</Text>
          <Image source={{ uri: data.image }} style={{ width: 200, height: 200 }} />
          <Text>préEvolution :</Text>
          {data.apiPreEvolution && data.apiPreEvolution.name ? (
            <TouchableOpacity onPress={() => handlePokemonPress(data.id - 1)}>
              <Text>{data.apiPreEvolution.name}</Text>
            </TouchableOpacity>
          ) : (
            <Text>aucune</Text>
          )}
          <Text>évolution : {data.apiEvolutions[0] ? (
            <TouchableOpacity onPress={() => handlePokemonPress(data.id + 1)}>
              <Text>{data.apiEvolutions[0].name}</Text>
            </TouchableOpacity>
          ) : "aucune"}</Text>
          <Image source={{ uri: data.sprite }} style={{ width: 100, height: 100 }} />
          <View style={styles.table}>
            {Object.entries(data.stats).map(([key, value]) => {
              return (
              <View key={key} style={styles.row}>
                <Text style={styles.label}>{key}</Text>
                <Text style={styles.value}>{value}</Text>
              </View>);
            })}
          </View>
        </View>
      ) : (
        <Text>Chargement des données...</Text>

      )}
    </>
  );
}

const styles = StyleSheet.create({
  table: {
    borderWidth: 1,
    borderColor: 'black',
    padding: 10,
    borderRadius: 5,
  },
  row: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    marginBottom: 5,
  },
  label: {
    fontWeight: 'bold',
  },
  value: {
    marginLeft: 10,
  },
});
export default PokedexDetails;
